final:
module RefModule(
    input wire clk,
    input wire load,
    input wire [7:0] data,
    output wire q
);

reg [7:0] unused_register;

always @(posedge clk) begin
    if (load)
        unused_register <= data;
    else
        unused_register <= unused_register >> 1;
end

assign q = unused_register[0];

endmodule
